  @api painter.hue(idx, chroma, light, alpha)  @ 299-302
      -- The idx-th perceptually-even hue. chroma/light/alpha tone it.
      @contract  returns an opaque colour token (not a bare int); pass to a draw method's colour arg.  @ 297
  @api painter.hueNative(idx)  @ 305-311
      @contract  REAPER native int (|0x1000000 set) for I_CUSTOMCOLOR; chroma/light match grid fill hue.  @ 304

